Here is a simple C++ function that uses the `std::regex` library to replace Markdown syntax with HTML. This function assumes that the Markdown syntax is basic and does not include any advanced features.

```cpp
#include <regex>
#include <string>

std::string markdownToHtml(const std::string& markdown) {
    std::string html;
    std::regex regexHeadline("^# (.*)$", std::regex::ECMAScript);
    std::regex regexItalic("^(?:__|\\*)(.*)\\1$");
    std::regex regexBold("^(?:\\*\\*|__)(.*)\\1$");
    std::regex regexLink("^(?:\\[(.*)\\]\\(([^)]+)\\))");
    std::regex regexImage("^(?:\\!(.*)\\[(.*)\\]\\(([^)]+)\\))");

    std::smatch match;

    if (std::regex_search(markdown, match, regexHeadline)) {
        html += "<h" + match[1].str().size() + ">"; // Convert # to h1, ## to h2, etc.
        html += match[1].str();
        html += "</h" + match[1].str().size() + ">\n";
    }

    while (std::regex_search(markdown, match, regexItalic)) {
        html += "<i>" + match[1].str() + "</i>\n";
        markdown = match.suffix().str();
    }

    while (std::regex_search(markdown, match, regexBold)) {
        html += "<b>" + match[1].str() + "</b>\n";
        markdown = match.suffix().str();
    }

    while (std::regex_search(markdown, match, regexLink)) {
        html += "<a href=\"" + match[2].str() + "\">" + match[1].str() + "</a>\n";
        markdown = match.suffix().str();
    }

    while (std::regex_search(markdown, match, regexImage)) {
        html += "<img src=\"" + match[3].str() + "\" alt=\"" + match[2].str() + "\">\n";
        markdown = match.suffix().str();
    }

    html += markdown;

    return html;
}
```

This function uses regular expressions to find and replace Markdown syntax with HTML. It supports the following Markdown syntax:

- Headings: `# Heading` becomes `<h1>Heading</h1>`
- Italic text: `*italic text*` becomes `<i>italic text</i>`
- Bold text: `**bold text**` becomes `<b>bold text</b>`
- Links: `[link text](http://www.example.com)` becomes `<a href="http://www.example.com">link text</a>`
- Images: `![image alt](http://www.example.com/image.jpg)` becomes `<img src="http://www.example.com/image.jpg" alt="image alt">`

Note that this is a very basic implementation and does not support all Markdown syntax.

